import unittest


class TwoSumTest(unittest.TestCase):
    def assert_indices(self, nums, target, result):
        self.assertEqual(len(result), 2)
        first, second = result
        self.assertNotEqual(first, second)
        self.assertEqual(nums[first] + nums[second], target)

    def test_example_one(self):
        self.assert_indices([2, 7, 11, 15], 9, two_sum([2, 7, 11, 15], 9))

    def test_example_two(self):
        self.assert_indices([3, 2, 4], 6, two_sum([3, 2, 4], 6))

    def test_duplicate_values(self):
        self.assert_indices([3, 3], 6, two_sum([3, 3], 6))

