def is_palindrome(x):
    text = str(x)
    return text == text[::-1]

test_code:
import unittest


class PalindromeNumberTest(unittest.TestCase):
    def test_positive_palindrome(self):
        self.assertIs(is_palindrome(121), True)

    def test_negative_number(self):
        self.assertIs(is_palindrome(-121), False)

    def test_not_palindrome(self):
        self.assertIs(is_palindrome(10), False)

    def test_single_digit(self):
        self.assertIs(is_palindrome(7), True)

