        self.assertIs(is_valid("()[]{}"), True)

    def test_wrong_order(self):
        self.assertIs(is_valid("(]"), False)

    def test_nested_pairs(self):
        self.assertIs(is_valid("{[]}"), True)

    def test_unclosed(self):
        self.assertIs(is_valid("(("), False)

